using System;
using System.IO;
using System.Windows.Media.Imaging;

namespace MCLauncher
{
    public static class EmbeddedAvatar
    {
        // Paste your base64 avatar image here (without the "data:image/jpeg;base64," prefix)
        private const string BASE64_AVATAR = "";

        public static BitmapImage GetAvatar()
        {
            if (string.IsNullOrEmpty(BASE64_AVATAR))
                return null;

            try
            {
                byte[] imageBytes = Convert.FromBase64String(BASE64_AVATAR);
                
                var bitmap = new BitmapImage();
                bitmap.BeginInit();
                bitmap.StreamSource = new MemoryStream(imageBytes);
                bitmap.CacheOption = BitmapCacheOption.OnLoad;
                bitmap.EndInit();
                bitmap.Freeze();
                
                return bitmap;
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine($"Failed to load embedded avatar: {ex.Message}");
                return null;
            }
        }
    }
}
